class Solution {
public:
    bool isPossible(vector<int>& target) {
        priority_queue<long long> pq;
        long long sum = 0;
        for (int i = 0; i < target.size(); i++) {
            sum += target[i];
            pq.push(target[i]);
        }
        while (pq.top() != 1) {
            long long x = pq.top();
            pq.pop();
            sum -= x;
            if (x <= sum || sum < 1) return false;
            x %= sum;
            if (x == 0) x = sum;
            sum += x;
            pq.push(x);
        }
        return true;
    }
};

